export async function POST(request: Request) {
  try {
    const { agent_type } = await request.json();

    if (!agent_type) {
      return Response.json({ error: 'agent_type is required' }, { status: 400 });
    }

    let result = '';

    if (agent_type === 'lead_finder') {
      result = `🔍 AI Lead Finder Results:\n\nFound 5 potential leads:\n1. Sarah J. - Tech Startup CEO - interested in automation\n2. Mike R. - Marketing Agency Owner - needs lead gen\n3. Lisa K. - Consulting Firm - looking for AI solutions\n4. Tom M. - E-commerce Business - wants to scale\n5. Jen P. - Local Service Business - ready for growth`;
    } else if (agent_type === 'appointment_scheduler') {
      result = `📅 Appointment Scheduler Results:\n\nScheduled 2 new appointments:\n1. John D. - Tomorrow at 2pm\n2. Maria S. - Friday at 10am`;
