      result = `📞 Follow-up Agent Results:\n\nSent follow-ups to 8 leads\n3 responses received`;
    } else {
      return Response.json({ error: 'Invalid agent_type' }, { status: 400 });
    }

    return Response.json({ success: true, result });
  } catch (error) {
    return Response.json({ error: 'Failed to run automation' }, { status: 500 });
  }
}
