Add a connection limit and use spatial optimization. Replace the nested loop with:
```tsx
// Limit connections per particle to avoid O(n²)
const maxConnections = 3;
let connections = 0;

// Inside draw(), replace the nested loop with:
particles.slice(i + 1).forEach((p2) => {
  if (connections >= maxConnections) return;
  const dx = p.x - p2.x;
  const dy = p.y - p2.y;
  const dist = Math.sqrt(dx * dx + dy * dy);
  if (dist < 150) {
    ctx.beginPath();
    ctx.moveTo(p.x, p.y);
    ctx.lineTo(p2.x, p2.y);
    ctx.strokeStyle = `rgba(249, 115, 22, ${0.15 * (1 - dist / 150)})`;
    ctx.stroke();
    connections++;
  }
});
