Add distance squared comparison to avoid expensive Math.sqrt calls, and cap the maximum connection distance check:
```tsx
// Replace the distance calculation with squared comparison
const maxDistSq = 150 * 150;
particles.slice(i + 1).forEach((p2) => {
  const dx = p.x - p2.x;
  const dy = p.y - p2.y;
  const distSq = dx * dx + dy * dy;

  if (distSq < maxDistSq) {
    ctx.beginPath();
    ctx.moveTo(p.x, p.y);
    ctx.lineTo(p2.x, p2.y);
    ctx.strokeStyle = `rgba(249, 115, 22, ${0.15 * (1 - Math.sqrt(distSq) / 150)})`;
    ctx.stroke();
  }
});
```

