```
async function fetchData() {
  setLoading(true);
  setError(null);
  try {
    const custRes = await fetch('/api/automation/customer');
    const custData = await custRes.json();
    if (custData.customer) setCustomer(custData.customer);

    const agentsRes = await fetch('/api/automation/agents');
    const agentsData = await agentsRes.json();
    if (agentsData.agents) setAgents(agentsData.agents);

    const resultsRes = await fetch('/api/automation/results');
    const resultsData = await resultsRes.json();
    if (resultsData.results) setResults(resultsData.results);
  } catch (e) {
    setError(e instanceof Error ? e.message : 'Failed to load data');
    console.error(e);
  }
  setLoading(false);
}
```

